import React, { useState } from 'react';
import ForestBackground from '../components/ForestBackground';
import FirefighterCharacter from '../components/FirefighterCharacter';
import DialogueBox from '../components/DialogueBox';
import { SCENES } from '../scenes';

const LEVELS = [
  { id:SCENES.FIREBREAK,       title:'Firebreaks',     emoji:'🪨', bg:'#E8A000', border:'#8B5E00', x:'18%', y:'42%' },
  { id:SCENES.NATIVE_PLANTS,   title:'Native Plants',  emoji:'🌸', bg:'#4CAF50', border:'#1B5E20', x:'38%', y:'32%' },
  { id:SCENES.GOATS,           title:'Goats',          emoji:'🐐', bg:'#8BC34A', border:'#33691E', x:'60%', y:'38%' },
  { id:SCENES.CONTROLLED_BURN, title:'Controlled Burn',emoji:'🔥', bg:'#FF5722', border:'#7F2700', x:'78%', y:'44%' },
];

const INTRO = [
  'Welcome to the Land Safety Map! Our forest needs your help!',
  'Wildfires spread fast through dry grass and dead plants. We need to protect our land!',
  'I will teach you 4 ways to keep the land safe. Click each area to learn and play!',
];

const WorldMapScreen = ({ navigateTo, completedLevels }) => {
  const [idx, setIdx] = useState(0);
  const [showDlg, setShowDlg] = useState(true);
  const next = () => idx < INTRO.length-1 ? setIdx(idx+1) : setShowDlg(false);
  const allDone = LEVELS.every(l => completedLevels.includes(l.id));

  return (
    <div style={{ width:'100vw', height:'100vh', position:'relative', overflow:'hidden' }}>
      <ForestBackground showPath timeOfDay="day"/>
      <div style={{ position:'absolute', top:14, left:'50%', transform:'translateX(-50%)', zIndex:20, textAlign:'center' }}>
        <div style={{ background:'rgba(22,65,12,0.95)', border:'4px solid #F5C518', borderRadius:22, padding:'10px 32px', boxShadow:'0 6px 24px rgba(0,0,0,0.4)' }}>
          <div style={{ fontFamily:"'Fredoka One',cursive", fontSize:28, color:'#F5C518' }}>Land Safety Map</div>
          <div style={{ fontFamily:"'Nunito',sans-serif", fontSize:13, color:'#a8e063', fontWeight:800 }}>{completedLevels.length}/{LEVELS.length} areas protected!</div>
        </div>
      </div>
      <div style={{ position:'absolute', top:88, left:'50%', transform:'translateX(-50%)', display:'flex', gap:10, zIndex:20 }}>
        {LEVELS.map((l,i) => <span key={i} style={{ fontSize:26, filter:completedLevels.includes(l.id)?'none':'grayscale(1) opacity(0.35)' }}>⭐</span>)}
      </div>
      {LEVELS.map((level,i) => {
        const done = completedLevels.includes(level.id);
        return (
          <div key={level.id} onClick={() => navigateTo(level.id)} style={{ position:'absolute', left:level.x, top:level.y, transform:'translate(-50%,-50%)', cursor:'pointer', zIndex:15, animation:'popIn 0.5s ease both', animationDelay:(i*0.12)+'s' }}>
            <div style={{ background:done?'#4CAF50':level.bg, border:'4px solid '+(done?'#1B5E20':level.border), borderBottom:'7px solid '+(done?'#1B5E20':level.border), borderRadius:18, padding:'12px 16px', textAlign:'center', minWidth:110, boxShadow:'0 6px 18px rgba(0,0,0,0.35)' }}>
              <div style={{ fontSize:30, marginBottom:4 }}>{done?'✅':level.emoji}</div>
              <div style={{ fontFamily:"'Fredoka One',cursive", fontSize:13, color:'white', textShadow:'1px 1px 2px rgba(0,0,0,0.5)' }}>{level.title}</div>
              {done && <div style={{ fontFamily:"'Nunito',sans-serif", fontSize:11, color:'#a8e063', fontWeight:800 }}>DONE! ⭐</div>}
            </div>
          </div>
        );
      })}
      <svg style={{ position:'absolute', inset:0, width:'100%', height:'100%', pointerEvents:'none', zIndex:8 }}>
        <path d="M 216 315 Q 380 270 456 240 Q 532 210 720 285 Q 780 310 936 330" stroke="#F5C518" strokeWidth="5" strokeDasharray="12 8" fill="none" opacity="0.65"/>
      </svg>
      {allDone && (
        <div style={{ position:'absolute', bottom:28, right:28, zIndex:30 }}>
          <button onClick={() => navigateTo(SCENES.VICTORY,'#F5C518')} style={{ background:'linear-gradient(135deg,#F5C518,#E8A000)', border:'4px solid #8B6914', borderBottom:'7px solid #8B6914', borderRadius:22, padding:'14px 28px', fontFamily:"'Fredoka One',cursive", fontSize:20, color:'#1a1a1a', cursor:'pointer', animation:'pulse 1.5s ease infinite' }}>
            See Your Results! 🏆
          </button>
        </div>
      )}
      <div style={{ position:'absolute', bottom:16, left:16, display:'flex', alignItems:'flex-end', gap:14, zIndex:25 }}>
        <FirefighterCharacter size={120} speaking={showDlg} expression="happy"/>
        {showDlg && <DialogueBox text={INTRO[idx]} onNext={next} style={{ maxWidth:340, marginBottom:16 }}/>}
      </div>
    </div>
  );
};
export default WorldMapScreen;
